// Layer A — `util-greetings` from layer 'greetings-a'.
//
// Both layer A and layer B install a module named `util-greetings`, so
// the integ exercises Lambda's "last layer wins on file collision"
// rule: when the function declares `[greetingsA, greetingsB]`, layer B
// must end up at /opt/nodejs/node_modules/util-greetings/index.js.
// cdkd merges the two layer asset dirs into one host tmpdir in
// template order (cpSync recursive+force) and bind-mounts that at
// /opt:ro — Docker rejects multiple -v ...:/opt:ro entries, so the
// merge must happen on the host, not via overlay layering.
module.exports = {
  greet: (name) => `from-layer-A:hello-${name}`,
  source: 'greetings-a',
};
